spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var cylW = 40;
    var cylH = 90;
    var cylX = (W - cylW) / 2;
    var cylY = H / 2 - 70;

    // Stages
    // 0 - 2s: 25% (1/4)
    // 2s - 4.5s: 50% (1/2)
    // 4.5s - 7s: 75% (3/4)
    // 7s - 9.5s: 100% (1/1)
    // 9.5s - 12s: Loop / Empty

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    var fillPercent = 0;
    var textFrac = '0/1';
    var textPct = '0%';
    var fillColor = '#60A5FA';

    if (stage === 1) {
      fillPercent = 0.25;
      textFrac = '1/4';
      textPct = '25%';
      fillColor = '#3B82F6';
    } else if (stage === 2) {
      fillPercent = 0.50;
      textFrac = '1/2';
      textPct = '50%';
      fillColor = '#10B981';
    } else if (stage === 3) {
      fillPercent = 0.75;
      textFrac = '3/4';
      textPct = '75%';
      fillColor = '#F59E0B';
    } else if (stage === 4) {
      fillPercent = 1.00;
      textFrac = '1/1';
      textPct = '100%';
      fillColor = '#8B5CF6';
    } else {
      // Smooth transition back to 0
      var drop = (progress - 0.79) / 0.21;
      fillPercent = 1.00 - drop;
      textFrac = '...';
      textPct = '...';
      fillColor = '#4B5563';
    }

    // Draw cylinder liquid
    var liquidH = cylH * fillPercent;
    ctx.fillStyle = fillColor;
    ctx.fillRect(cylX, cylY + (cylH - liquidH), cylW, liquidH);

    // Draw cylinder border
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 3;
    ctx.strokeRect(cylX, cylY, cylW, cylH);

    // Draw tick marks at 25%, 50%, 75%, 100%
    var ticks = [0.25, 0.50, 0.75, 1.00];
    var tickFracs = ['1/4', '1/2', '3/4', '1'];
    var tickPcts = ['25%', '50%', '75%', '100%'];
    ctx.font = '10px -apple-system, sans-serif';
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';

    for (var i = 0; i < ticks.length; i++) {
      var ty = cylY + cylH - cylH * ticks[i];
      ctx.beginPath();
      ctx.moveTo(cylX - 5, ty);
      ctx.lineTo(cylX, ty);
      ctx.strokeStyle = '#6B7280';
      ctx.lineWidth = 1.5;
      ctx.stroke();

      // Fraction on left
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText(tickFracs[i], cylX - 8, ty);
    }

    ctx.textAlign = 'left';
    for (var i = 0; i < ticks.length; i++) {
      var ty = cylY + cylH - cylH * ticks[i];
      ctx.beginPath();
      ctx.moveTo(cylX + cylW, ty);
      ctx.lineTo(cylX + cylW + 5, ty);
      ctx.strokeStyle = '#6B7280';
      ctx.lineWidth = 1.5;
      ctx.stroke();

      // Percent on right
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText(tickPcts[i], cylX + cylW + 8, ty);
    }

    // Text labels at bottom
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 18px -apple-system, sans-serif';
    ctx.fillStyle = fillColor;
    ctx.fillText(textFrac + '   =   ' + textPct, W / 2, H - 42);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';
    if (stage === 1) ctx.fillText('Quarter full: 1/4 = 25%', W / 2, H - 22);
    else if (stage === 2) ctx.fillText('Half full: 1/2 = 50%', W / 2, H - 22);
    else if (stage === 3) ctx.fillText('Three-quarters full: 3/4 = 75%', W / 2, H - 22);
    else if (stage === 4) ctx.fillText('Completely full: 1/1 = 100%', W / 2, H - 22);
    else ctx.fillText('Resetting scale...', W / 2, H - 22);
  }
};
